import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function RoleManagement() {
  const [roles, setRoles] = useState([]);
  const [permissions, setPermissions] = useState([]);
  const [selectedPermissions, setSelectedPermissions] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    name: "",
    description: "",
  });

  const [filters, setFilters] = useState({ search: "" });
  const [currentPage, setCurrentPage] = useState(1);
  const rolesPerPage = 10;

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH ROLES ================= */
  function fetchRoles() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/roles", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setRoles(res.data.data);
        }
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching roles")
      )
      .finally(() => setLoading(false));
  }

  /* ================= FETCH PERMISSIONS ================= */
  function fetchPermissions() {
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/permissions", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setPermissions(res.data.data);
        }
      })
      .catch(() => toast.error("Error fetching permissions"));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else {
      fetchRoles();
      fetchPermissions();
    }
  }, [navigate]);

  /* ================= INPUT ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= PERMISSION ================= */
  function handlePermissionChange(permissionId) {
    setSelectedPermissions((prev) =>
      prev.includes(permissionId)
        ? prev.filter((id) => id !== permissionId)
        : [...prev, permissionId]
    );
  }

  /* ================= ADD ================= */
  function openAddModal() {
    setFormData({
      id: null,
      name: "",
      description: "",
    });
    setSelectedPermissions([]);

    const modalEl = document.getElementById("roleModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= EDIT ================= */
  function openEditModal(role) {
    setFormData({
      id: role.id,
      name: role.name || "",
      description: role.description || "",
    });

    const permissionIds =
      role.permissions?.map((p) => p.id) || [];

    setSelectedPermissions(permissionIds);

    const modalEl = document.getElementById("roleModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    const token = Cookies.get("adminToken");

    if (!window.confirm("Are you sure you want to delete this role?")) return;

    axios
      .delete(API_BASE_URL + "/roles/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Role deleted successfully");
        fetchRoles();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Delete failed")
      );
  }

  /* ================= SUBMIT (SAFE UPDATE) ================= */
  function handleSubmit(e) {
    e.preventDefault();

    const trimmedName = formData.name.trim();

    if (!trimmedName) {
      toast.error("Role name is required");
      return;
    }

    const token = Cookies.get("adminToken");

    const payload = {
      name: trimmedName,
      description: formData.description?.trim() || null,
      permissions: selectedPermissions,
    };

    const request = formData.id
      ? axios.put(API_BASE_URL + "/roles/" + formData.id, payload, {
          headers: { Authorization: "Bearer " + token },
        })
      : axios.post(API_BASE_URL + "/roles", payload, {
          headers: { Authorization: "Bearer " + token },
        });

    request
      .then(() => {
        toast.success(
          formData.id
            ? "Role updated successfully"
            : "Role created successfully"
        );

        fetchRoles();
        modalRef.current.hide();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Operation failed")
      );
  }

  /* ================= FILTERED DATA ================= */
  const filteredRoles = roles.filter((role) =>
    filters.search
      ? (role.name + role.description)
          .toLowerCase()
          .includes(filters.search.toLowerCase())
      : true
  );

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * rolesPerPage;
  const indexOfFirst = indexOfLast - rolesPerPage;
  const currentRoles = filteredRoles.slice(indexOfFirst, indexOfLast);

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      {/* Header */}
      <div className="d-flex justify-content-between mb-3">
        <h4 className="fw-bold">Roles</h4>
        <button className="btn btn-primary btn-sm" onClick={openAddModal}>
          + Add Role
        </button>
      </div>

      {/* Table */}
      <div className="card border-0">
        <div className="card-body p-0">
          {loading ? (
            <div className="text-center p-3">Loading...</div>
          ) : (
            <div className="table-responsive">
              <table className="table table-striped small">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Description</th>
                    <th>Permissions</th>
                    <th>Created</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentRoles.map((role) => (
                    <tr key={role.id}>
                      <td>{role.id}</td>
                      <td>{role.name}</td>
                      <td>{role.description}</td>
                      <td>
                        {role.permissions?.map((p) => (
                          <span
                            key={p.id}
                            className="badge bg-primary me-1 mb-1"
                          >
                            {p.key}
                          </span>
                        ))}
                      </td>
                      <td>
                        {dayjs(role.createdAt).format(
                          "DD MMM YYYY, hh:mm A"
                        )}
                      </td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => openEditModal(role)}
                        ></i>
                        <i
                          className="fa-solid fa-trash text-danger"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleDelete(role.id)}
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* Modal */}
      <div className="modal fade" id="roleModal" tabIndex="-1">
        <div className="modal-dialog modal-lg modal-dialog-centered">
          <div className="modal-content border-0">
            <div className="modal-header">
              <h5 className="modal-title">
                {formData.id ? "Edit Role" : "Add Role"}
              </h5>
              <button
                type="button"
                className="btn-close"
                data-bs-dismiss="modal"
              ></button>
            </div>

            <div className="modal-body">
              <div className="mb-3">
                <label className="form-label small text-muted">
                  Role Name *
                </label>
                <input
                  type="text"
                  name="name"
                  className="form-control form-control-sm"
                  value={formData.name}
                  onChange={handleInputChange}
                />
              </div>

              <div className="mb-3">
                <label className="form-label small text-muted">
                  Description
                </label>
                <textarea
                  name="description"
                  className="form-control form-control-sm"
                  rows="2"
                  value={formData.description}
                  onChange={handleInputChange}
                />
              </div>

              <label className="form-label small text-muted">
                Permissions
              </label>

              <div className="row">
                {permissions.map((perm) => (
                  <div className="col-md-4" key={perm.id}>
                    <div className="form-check">
                      <input
                        className="form-check-input"
                        type="checkbox"
                        checked={selectedPermissions.includes(perm.id)}
                        onChange={() =>
                          handlePermissionChange(perm.id)
                        }
                      />
                      <label className="form-check-label small">
                        {perm.key}
                      </label>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="modal-footer">
              <button
                className="btn btn-secondary btn-sm"
                data-bs-dismiss="modal"
              >
                Cancel
              </button>
              <button
                className="btn btn-primary btn-sm"
                onClick={handleSubmit}
              >
                {formData.id ? "Update Role" : "Create Role"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default RoleManagement;
